const BUILDLINK="https://eliteserving.github.io/BUILD/";
window.FEATURES=FEATURES();
const TITLE = document.title;
const PROJECTLOADER=(NAME)=>{
    const DEV=localStorage.getItem("ENV");
    switch (DEV) {
        case "ANDROID":import(BUILDLINK+NAME+"/ANDROID/index.js");
            break;
        case "DESKTOP":import(BUILDLINK+NAME+"/DESKTOP/index.js");
            break;
        case "WEB":import(BUILDLINK+NAME+"/WEB/index.js");
            break;
        default:import("../DEVELOPMENT/index.js");
            break;
    };
    const DATA=`ROUTED(localStorage.getItem("CLOUDNATIVE"));ROUTED(localStorage.getItem("AUTORUN"));ROUTED(localStorage.getItem("NATIVE"));`;
    localStorage.setItem("NATIVER",DATA);
    const DATA2=`BODIED();`;
    localStorage.setItem("AUTORUN",DATA2);
    localStorage.setItem("Native",new Date());
};
const DEVPROJECTLOADER=()=>{
    import("../DEVELOPMENT/index.js");
    const DATA=`ROUTED(localStorage.getItem("CLOUDNATIVE"));ROUTED(localStorage.getItem("AUTORUN"));ROUTED(localStorage.getItem("NATIVE"));`;
    localStorage.setItem("NATIVER",DATA);
    const DATA2=`BODIED();`;
    localStorage.setItem("AUTORUN",DATA2);
    localStorage.setItem("Native",new Date());
};
const PROJECTCONNECTOR=()=>{
    switch (TITLE) {
        case "EliteBuilder":DEVPROJECTLOADER();
            break;
        case "Elite_Robust_Ontology":PROJECTLOADER("MAIN");
            break;
        case "Cinefy":PROJECTLOADER("CINEFY");
            break;
        case "Noor_Charity_And_Orphanage_Organisation":PROJECTLOADER("NOOR");
            break;
        case "Tafyz_Craft_Limited":PROJECTLOADER("TAFYZ");
            break;   
        case "ShyLanSirajFashionHub":PROJECTLOADER("NOORFASHION");
            break;  
        case "NaweriTenat":PROJECTLOADER("NAWERITENAT");
            break; 
        case "EliteManager":PROJECTLOADER("MANAGER");
            break; 
        case "Qel_Medistore_Limited":PROJECTLOADER("QEL");
            break; 
        default:
            break;
    };
};
